@import "tailwindcss";

@theme {
  /* palette (mined, ranked by usage) */
  --color-neutral-50: #ffffff;
  --color-neutral-100: #f3f3f3;
  --color-neutral-200: #d4d4d4;
  --color-neutral-400: #979797;
  --color-neutral-700: #545454;
  --color-neutral-950: #000000;
  --color-green: #127749;
  --color-green-2: #329066;
  --color-deep-green: #006139;

  /* inferred semantic roles (each maps to a distinct mined value) */
  --color-canvas: #ffffff;
  --color-ink: #000000;
  --color-text-muted: #979797;
  --color-surface: #f3f3f3;
  --color-hairline: #d4d4d4;
  --color-accent: #127749;
  --color-accent-2: #329066;
  --color-accent-3: #006139;

  --font-sans: "RolexFont-XL", ui-sans-serif, system-ui, sans-serif;

  --text-xs: 0.625rem;
  --text-sm: 0.75rem;
  --text-base: 0.875rem;
  --text-lg: 0.93rem;
  --text-xl: 1rem;
  --text-2xl: 1.125rem;
  --text-3xl: 1.18rem;
  --text-4xl: 2rem;

  --font-weight-light: 300;
  --font-weight-normal: 400;
  --font-weight-bold: 700;
  --font-weight-750: 750;

  /* line-heights, sorted tight -> loose */
  --leading-none: 1;
  --leading-tight: 1.14;
  --leading-snug: 1.15;
  --leading-normal: 1.25;
  --leading-relaxed: 1.38;
  --leading-loose: 1.43;
  --leading-looser: 1.5;
  --leading-loosest: 2.5;

  /* letter-spacing, sorted tight -> wide */
  --tracking-tightest: 0.125em;

  --radius-sm: 0.38rem;
  --radius-md: 0.625rem;
  --radius-lg: 50px;
  --radius-full: 9999px;

  /* shadows, sorted by blur */
  --shadow-sm: 0 4px 28px 0 rgba(0, 0, 0, 0.1);

  --breakpoint-sm: 30rem;
  --breakpoint-md: 47.9375rem;
  --breakpoint-lg: 48rem;
  --breakpoint-xl: 56rem;
  --breakpoint-2xl: 64.0625rem;
  --breakpoint-3xl: 80rem;
  --breakpoint-4xl: 90rem;
  --breakpoint-5xl: 100rem;

  /* most-used spacing values on the source site (px): 8, 10, 11, 13, 14, 16, 20, 24, 30, 35, 40, 60 */
}

/* dark-mode values mined from the source (native token names) */
@media (prefers-color-scheme: dark) {
  :root {
    --text: inherit;
    --container: rgb(var(--dark-grey) / 0.3);
  }
}

